// Validate the Fetch Project result
const items = $input.all();
const item = items[0]?.json || {};

// Check for HTTP/Airtable error
if (item.error || item.errorMessage || !item.id) {
  const inputBody = $('Webhook Trigger').first().json;
  const recordId = inputBody.body ? inputBody.body.recordId : inputBody.recordId;
  return [{
    json: {
      projectFound: false,
      errorMessage: item.error || item.errorMessage || `No project found for recordId: ${recordId || 'undefined'}`,
      recordId: recordId || 'unknown'
    }
  }];
}

return [{
  json: {
    projectFound: true,
    ...item
  }
}];

// Build error log entry for project-not-found
const prev = $input.first().json;
const now = new Date().toISOString();
const message = prev.errorMessage || 'Project not found';

return [{
  json: {
    recordId: prev.recordId || null,
    pipelineLog: `[${now}] ✗ PROMPT ERROR: ${message}`,
    errorMessage: message,
    status: 'structure_selected'
  }
}];

// Return error response to webhook caller
const prev = $input.first().json;
return [{
  json: {
    success: false,
    error: 'Project fetch failed',
    message: prev.fields ? prev.fields['Pipeline Log'] : $('Code — Build Error Log (Project)').first().json.errorMessage
  }
}];

// Validate LLM response — V4: reverse deconstruction edit prompts + canon image data
const llmResponse = $input.first().json;
const projectRecordId = $('Code — Build LLM Prompt').first().json.projectRecordId;
const brandName = $('Code — Build LLM Prompt').first().json.brandName;
const canonDriveFileId = $('Code — Build LLM Prompt').first().json.canonDriveFileId || '';
const canonDriveUrl = $('Code — Build LLM Prompt').first().json.canonDriveUrl || '';

// Check for HTTP-level error from Groq
if (llmResponse.error || llmResponse.statusCode >= 400 || !llmResponse.choices) {
  const httpError = llmResponse.error?.message || llmResponse.message || llmResponse.error || `HTTP ${llmResponse.statusCode || 'unknown'} from Groq`;
  return [{
    json: {
      llmOk: false,
      projectRecordId,
      brandName,
      errorMessage: `Groq LLM call failed: ${httpError}`
    }
  }];
}

// Parse the LLM response
try {
  const rawText = llmResponse.choices[0].message.content;
  const data = typeof rawText === 'object' ? rawText : JSON.parse(rawText);

  if (!data.edit_prompts || data.edit_prompts.length !== 7) {
    throw new Error(`Expected 7 edit prompts, got ${data.edit_prompts ? data.edit_prompts.length : 0}`);
  }
  if (!data.videos || data.videos.length !== 4) {
    throw new Error(`Expected 4 video prompts, got ${data.videos ? data.videos.length : 0}`);
  }

  // Stage mapping for image phases
  const imageStageMap = { 8: 1, 7: 1, 6: 2, 5: 2, 4: 3, 3: 3, 2: 4, 1: 4 };
  const videoStageMap = { 1: 4, 2: 3, 3: 2, 4: 1 };

  const records = [];

  // Phase 8 canon image record — include canon image data so it shows in the table
  records.push({
    json: {
      llmOk: true,
      projectRecordId,
      phaseNumber: 8,
      assetType: 'image',
      phaseLabel: 'Iconic Brand Reveal',
      promptLabel: `${brandName} - Phase 8 (image)`,
      promptText: 'Canon image — user-created hero image',
      generationStatus: 'generated',
      stage: 1,
      brandName,
      driveFileId: canonDriveFileId,
      driveUrl: canonDriveFileId ? `https://drive.google.com/file/d/${canonDriveFileId}/view` : ''
    }
  });

  // 7 edit prompt records
  for (const ep of data.edit_prompts) {
    records.push({
      json: {
        llmOk: true,
        projectRecordId,
        phaseNumber: ep.phase,
        assetType: 'image',
        phaseLabel: ep.label,
        promptLabel: `${brandName} - Phase ${ep.phase} (image)`,
        promptText: ep.edit_prompt,
        generationStatus: 'pending',
        stage: imageStageMap[ep.phase] || 1,
        brandName,
        driveFileId: '',
        driveUrl: ''
      }
    });
  }

  // 4 video records
  for (const vid of data.videos) {
    records.push({
      json: {
        llmOk: true,
        projectRecordId,
        phaseNumber: vid.phase,
        assetType: 'video',
        phaseLabel: vid.label,
        promptLabel: `${brandName} - Phase ${vid.phase} (video)`,
        promptText: vid.prompt,
        generationStatus: 'pending',
        stage: videoStageMap[vid.phase] || 1,
        brandName,
        driveFileId: '',
        driveUrl: ''
      }
    });
  }

  return records;
} catch (error) {
  return [{
    json: {
      llmOk: false,
      projectRecordId,
      brandName,
      errorMessage: `Failed to parse LLM response: ${error.message}`
    }
  }];
}

// Build error log entry for LLM failure
const prev = $input.first().json;
const now = new Date().toISOString();
const message = prev.errorMessage || 'LLM response validation failed';

return [{
  json: {
    recordId: prev.projectRecordId,
    pipelineLog: `[${now}] ✗ PROMPT ERROR: ${message}`,
    errorMessage: message,
    status: 'structure_selected'
  }
}];

// Return error response to webhook caller
const errorLog = $('Code — Build Error Log (LLM)').first().json;
return [{
  json: {
    success: false,
    error: 'Prompt generation failed',
    message: errorLog.errorMessage
  }
}];

// Build success log entry — V3: 7 edit + 4 video + 1 canon = 12 records
const projectRecordId = $('Code — Validate Project').first().json.id;
const brandName = $('Code — Build LLM Prompt').first().json.brandName;
const allItems = $('Code — Validate LLM Response').all();
const imageCount = allItems.filter(i => i.json.assetType === 'image').length;
const videoCount = allItems.filter(i => i.json.assetType === 'video').length;
const editCount = imageCount - 1; // subtract Phase 8 canon
const now = new Date().toISOString();

return [{
  json: {
    projectRecordId,
    brandName,
    pipelineLog: `[${now}] ✓ Prompt Generation complete (${imageCount + videoCount}/${imageCount + videoCount} prompts created: ${editCount} edit + ${videoCount} video + Phase 8 canon)`
  }
}];

// Return success response to webhook caller
const successLog = $('Code — Build Success Log').first().json;
return [{
  json: {
    success: true,
    message: successLog.pipelineLog,
    brandName: successLog.brandName
  }
}];
